    21→  const serverUrl = document.getElementById('server-url').value.trim() || 'http://localhost:3456';
    22→
    23→  await chrome.storage.local.set({ jiraHost, serverUrl });
    24→
    25→  const msg = document.getElementById('saved-msg');
    26→  msg.style.display = 'inline';
    27→  setTimeout(() => { msg.style.display = 'none'; }, 2000);
    28→}
    29→
    30→async function loadBoardConfigs() {
    31→  const all = await chrome.storage.local.get(null);
    32→  const container = document.getElementById('boards-list');
    33→  container.innerHTML = '';
    34→
    35→  const boardKeys = Object.keys(all).filter(k => k.startsWith('boardConfig_'));
    36→
    37→  if (boardKeys.length === 0) {
    38→    container.innerHTML = '<p style="color: #6b778c; font-size: 13px;">No boards configured yet. Visit a Jira board to set one up.</p>';
    39→    return;
    40→  }
    41→
    42→  for (const key of boardKeys) {
    43→    const config = all[key];
    44→    const item = document.createElement('div');
    45→    item.className = 'board-item';
    46→    item.innerHTML = `
    47→      <div>
    48→        <strong>Board ${config.boardId}</strong> (${config.projectKey || '?'})
    49→      </div>
    50→      <button data-key="${key}">Remove</button>
    51→    `;
    52→    item.querySelector('button').addEventListener('click', async () => {
    53→      await chrome.storage.local.remove(key);
    54→      loadBoardConfigs();
    55→    });
    56→    container.appendChild(item);
    57→  }
    58→}
