   144→async function setupChromeMock(page: Page) {
   145→  await page.evaluate(() => {
   146→    (window as any).__jiranimoStorage = {};
   147→    (window as any).chrome = {
   148→      storage: {
   149→        local: {
   150→          get: (keys: string | string[]) => {
   151→            const s = (window as any).__jiranimoStorage;
   152→            const result: Record<string, unknown> = {};
   153→            const keyList = Array.isArray(keys) ? keys : typeof keys === 'string' ? [keys] : [];
   154→            for (const k of keyList) { if (s[k] !== undefined) result[k] = s[k]; }
   155→            return Promise.resolve(result);
   156→          },
   157→          set: (items: Record<string, unknown>) => {
   158→            Object.assign((window as any).__jiranimoStorage, items);
   159→            return Promise.resolve();
   160→          },
   161→          remove: (key: string) => {
   162→            delete (window as any).__jiranimoStorage[key];
   163→            return Promise.resolve();
   164→          },
   165→        },
   166→        onChanged: { addListener: () => {} },
   167→      },
   168→      runtime: {
   169→        sendMessage: (msg: any, cb?: Function) => {
   170→          const respond = (data: any) => { if (cb) cb(data); };
   171→          setTimeout(() => {
   172→            if (msg.type === 'get-board-columns') respond({ columns: ['To Do', 'In Progress', 'testos', 'in review', 'Done'] });
   173→            else if (msg.type === 'get-transitions') respond({ transitions: [{ id: '11', name: 'To Do' }, { id: '21', name: 'In Progress' }, { id: '31', name: 'Done' }] });
   174→            else if (msg.type === 'implement-task') respond({ success: true });
   175→            else respond({});
   176→          }, 50);
   177→        },
   178→        onMessage: { addListener: () => {} },
   179→      },
   180→    };
   181→  });
   182→}
